import argparse
import json
import os
import sys
import time
from typing import Any, Dict

import pika

RABBITMQ_HOST = os.getenv("RABBITMQ_HOST", "localhost")
RABBITMQ_PORT = int(os.getenv("RABBITMQ_PORT", "5672"))
QUEUE_NAME = os.getenv("RABBITMQ_QUEUE", "task_queue")


def get_connection() -> pika.BlockingConnection:
    credentials = pika.PlainCredentials(
        os.getenv("RABBITMQ_USER", "guest"),
        os.getenv("RABBITMQ_PASSWORD", "guest"),
    )
    parameters = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        heartbeat=60,
        blocked_connection_timeout=300,
    )
    return pika.BlockingConnection(parameters)


def declare_queue(channel: pika.adapters.blocking_connection.BlockingChannel) -> None:
    channel.queue_declare(queue=QUEUE_NAME, durable=True)


def publish_task(task: Dict[str, Any]) -> None:
    connection = get_connection()
    try:
        channel = connection.channel()
        declare_queue(channel)
        body = json.dumps(task).encode("utf-8")
        channel.basic_publish(
            exchange="",
            routing_key=QUEUE_NAME,
            body=body,
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json",
            ),
        )
        print(f" [x] Sent {task}")
    finally:
        connection.close()


def process_task(task: Dict[str, Any]) -> None:
    task_type = task.get("type", "default")
    payload = task.get("payload", {})
    duration = float(task.get("duration", 1))
    print(f" [>] Processing task type={task_type} payload={payload} duration={duration}")
    time.sleep(duration)
    print(f" [v] Done processing task type={task_type}")


def consume_tasks() -> None:
    connection = get_connection()
    channel = connection.channel()
    declare_queue(channel)
    channel.basic_qos(prefetch_count=1)

    def callback(ch, method, properties, body):
        try:
            task = json.loads(body.decode("utf-8"))
            process_task(task)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f" [!] Error processing message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)
    print(" [*] Waiting for messages. To exit press CTRL+C")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print(" [x] Consumer stopped")
    finally:
        if not connection.is_closed:
            connection.close()


def parse_task_args(args: list[str]) -> Dict[str, Any]:
    task_type = args[0] if len(args) >= 1 else "default"
    payload_str = args[1] if len(args) >= 2 else "{}"
    duration = float(args[2]) if len(args) >= 3 else 1.0
    try:
        payload = json.loads(payload_str)
    except json.JSONDecodeError:
        payload = {"value": payload_str}
    return {
        "type": task_type,
        "payload": payload,
        "duration": duration,
        "created_at": time.time(),
    }


def main() -> None:
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher/consumer")
    subparsers = parser.add_subparsers(dest="command", required=True)

    publish_parser = subparsers.add_parser("publish", help="Publish a task message")
    publish_parser.add_argument("task_type", nargs="?", default="default")
    publish_parser.add_argument("payload", nargs="?", default="{}")
    publish_parser.add_argument("duration", nargs="?", default="1.0")

    subparsers.add_parser("consume", help="Consume task messages")

    args = parser.parse_args()

    if args.command == "publish":
        task = parse_task_args([args.task_type, args.payload, args.duration])
        publish_task(task)
    elif args.command == "consume":
        consume_tasks()


